// roundMoney.ts  — banker's rounding (round half to even), float-safe
export function roundMoney(amount: number, decimals = 2): number {
  if (!Number.isFinite(amount)) {
    throw new RangeError('amount must be finite');
  }
  const factor = 10 ** decimals;
  const sign = Math.sign(amount);
  const scaled = Math.abs(amount) * factor;

  // Nudge away binary representation error (e.g. 1.005*100 = 100.4999...).
  const corrected = scaled + Number.EPSILON * scaled;

  const floor = Math.floor(corrected);
  const diff = corrected - floor;

  let roundedAbs: number;
  const EXACT_HALF = 1e-9; // tolerance band for the tie case
  if (Math.abs(diff - 0.5) < EXACT_HALF) {
    // Tie: round to even.
    roundedAbs = floor % 2 === 0 ? floor : floor + 1;
  } else {
    roundedAbs = Math.round(corrected);
  }

  // Avoid returning -0 for inputs that round to zero.
  const result = (sign * roundedAbs) / factor;
  return result === 0 ? 0 : result;
}

// roundMoney.test.ts
import { roundMoney } from './roundMoney';

describe('roundMoney', () => {
  it('leaves an already-rounded value unchanged', () => {
    expect(roundMoney(1.23)).toBe(1.23);
  });

  it('rounds normal values to 2 decimals', () => {
    expect(roundMoney(1.236)).toBe(1.24);
    expect(roundMoney(1.234)).toBe(1.23);
  });

  it('uses banker\u2019s rounding on exact ties', () => {
    expect(roundMoney(2.5, 0)).toBe(2);   // down to even\n    expect(roundMoney(3.5, 0)).toBe(4);   // up to even\n    expect(roundMoney(0.125, 2)).toBe(0.12); // 12 is even\n    expect(roundMoney(0.135, 2)).toBe(0.14); // 14 is even\n  });

  it('handles the 1.005 float trap', () => {
    expect(roundMoney(1.005, 2)).toBe(1.0); // tie -> even (1.00)
  });

  it('rounds negatives symmetrically', () => {
    expect(roundMoney(-2.5, 0)).toBe(-2);
    expect(roundMoney(-1.236)).toBe(-1.24);
    expect(Object.is(roundMoney(-0.001), 0)).toBe(true); // no -0
  });

  it('rejects non-finite input', () => {
    expect(() => roundMoney(Infinity)).toThrow(RangeError);
  });
});

// types.ts
export interface UserRepo {
  findByEmail(email: string): Promise<User | null>;
  save(user: User): Promise<void>;
}
export interface Mailer { sendWelcome(email: string): Promise<void>; }
export interface User { id: string; email: string; }

// registerUser.ts
export class DuplicateEmailError extends Error {}

export async function registerUser(
  email: string,
  deps: { repo: UserRepo; mailer: Mailer; id: () => string },
): Promise<User> {
  const existing = await deps.repo.findByEmail(email);
  if (existing) throw new DuplicateEmailError(email);

  const user: User = { id: deps.id(), email };
  await deps.repo.save(user);          // persist
  await deps.mailer.sendWelcome(email); // side effect
  return user;
}

// registerUser.test.ts
import { registerUser, DuplicateEmailError } from './registerUser';
import type { UserRepo, Mailer, User } from './types';

// FAKE: a real, simplified repository keyed by email
class InMemoryUserRepo implements UserRepo {
  private byEmail = new Map<string, User>();
  async findByEmail(email: string) { return this.byEmail.get(email) ?? null; }
  async save(user: User) { this.byEmail.set(user.email, user); }
}

describe('registerUser', () => {
  const makeMailer = () => ({ sendWelcome: jest.fn().mockResolvedValue(undefined) });

  it('persists the user and sends one welcome email', async () => {
    const repo = new InMemoryUserRepo();
    const mailer = makeMailer();

    const user = await registerUser('a@x.com', { repo, mailer, id: () => 'u1' });

    // verify persistence by reading STATE back from the fake
    expect(await repo.findByEmail('a@x.com')).toEqual(user);
    // verify the SIDE EFFECT with a spy — behavior, not call order
    expect(mailer.sendWelcome).toHaveBeenCalledTimes(1);
    expect(mailer.sendWelcome).toHaveBeenCalledWith('a@x.com');
  });

  it('rejects a duplicate email and sends no email', async () => {
    const repo = new InMemoryUserRepo();
    const mailer = makeMailer();
    await repo.save({ id: 'u0', email: 'a@x.com' }); // pre-seed

    await expect(
      registerUser('a@x.com', { repo, mailer, id: () => 'u1' }),
    ).rejects.toBeInstanceOf(DuplicateEmailError);

    expect(mailer.sendWelcome).not.toHaveBeenCalled();
  });
});

// rateLimiter.ts — clock injected so time is deterministic
export interface Clock { now(): number; }

export class SlidingWindowRateLimiter {
  private hits = new Map<string, number[]>();

  constructor(
    private readonly limit: number,
    private readonly windowMs: number,
    private readonly clock: Clock = { now: () => Date.now() },
  ) {}

  allow(key: string): boolean {
    const t = this.clock.now();
    const cutoff = t - this.windowMs;
    const recent = (this.hits.get(key) ?? []).filter((ts) => ts > cutoff);
    if (recent.length >= this.limit) {
      this.hits.set(key, recent); // keep pruned list, reject
      return false;
    }
    recent.push(t);
    this.hits.set(key, recent);
    return true;
  }
}

// rateLimiter.test.ts — fake clock, no real time
import { SlidingWindowRateLimiter, Clock } from './rateLimiter';

class FakeClock implements Clock {
  private t = 0;
  now() { return this.t; }
  advance(ms: number) { this.t += ms; }
}

describe('SlidingWindowRateLimiter', () => {
  it('allows up to the limit and denies the next call in the window', () => {
    const clock = new FakeClock();
    const limiter = new SlidingWindowRateLimiter(3, 1000, clock);

    expect(limiter.allow('k')).toBe(true);  // 1
    expect(limiter.allow('k')).toBe(true);  // 2
    expect(limiter.allow('k')).toBe(true);  // 3
    expect(limiter.allow('k')).toBe(false); // 4th within window -> denied
  });

  it('allows again once the window has fully elapsed', () => {
    const clock = new FakeClock();
    const limiter = new SlidingWindowRateLimiter(1, 1000, clock);

    expect(limiter.allow('k')).toBe(true);
    expect(limiter.allow('k')).toBe(false); // still inside the window

    clock.advance(1001);                    // move past windowMs instantly
    expect(limiter.allow('k')).toBe(true);  // window reset
  });

  it('tracks keys independently', () => {
    const clock = new FakeClock();
    const limiter = new SlidingWindowRateLimiter(1, 1000, clock);
    expect(limiter.allow('a')).toBe(true);
    expect(limiter.allow('b')).toBe(true);  // different key, own window
    expect(limiter.allow('a')).toBe(false);
  });
});

// order.ts
export interface Order {
  id: string;
  customerTenureDays: number;
  totalCents: number;
  itemCount: number;
  country: string;
  isGift: boolean;
}

export function isEligibleForDiscount(order: Order): boolean {
  const loyal = order.customerTenureDays >= 90;
  const highValue = order.totalCents >= 10_000;
  return loyal && highValue;
}

// orderBuilder.ts — fluent test data builder with valid defaults
export class OrderBuilder {
  private order: Order = {
    id: 'order-1',
    customerTenureDays: 365,   // loyal by default
    totalCents: 20_000,        // high-value by default
    itemCount: 2,
    country: 'US',
    isGift: false,
  };

  withTenureDays(days: number): this { this.order.customerTenureDays = days; return this; }
  withTotalCents(cents: number): this { this.order.totalCents = cents; return this; }
  asGift(): this { this.order.isGift = true; return this; }
  build(): Order { return { ...this.order }; }
}

export const anOrder = () => new OrderBuilder();

// isEligibleForDiscount.test.ts
import { isEligibleForDiscount } from './order';
import { anOrder } from './orderBuilder';

describe('isEligibleForDiscount', () => {
  it('is eligible for a loyal, high-value order', () => {
    const order = anOrder()
      .withTenureDays(120)      // the only fields this behavior cares about
      .withTotalCents(15_000)
      .build();
    expect(isEligibleForDiscount(order)).toBe(true);
  });

  it('is not eligible for a brand-new customer', () => {
    const order = anOrder()
      .withTenureDays(5)        // override only the relevant field
      .build();                 // total stays high-value by default
    expect(isEligibleForDiscount(order)).toBe(false);
  });
});
